(* top =  1  *)
module top(rst, clk, \initial );
  reg \initial  = 0;
  input clk;
  input \initial ;
  reg \output ;
  reg \output$next ;
  input rst;
  always @* begin
    if (\initial ) begin end
    \output$next  = \output ;
    \output$next  = \initial ;
    casez (rst)
      1'h1:
          \output$next  = 1'h0;
    endcase
  end
  initial begin
      \output  <= 1'h0;
  end
  always @(posedge clk) begin
      \output  <= \output$next ;
  end
endmodule
